const XLSX = require\('xlsx'\);

const COLUMN_MAP = {
  'Nombre del producto':     'nombreProducto',
  'Descripción de la pieza': 'descripcionPieza',
  'Número de pieza':         'numeroPieza',
  'Pieza secundaria':        'piezaSecundaria',
  'Precio de intercambio':   'precioIntercambio',
};

function mapRawRow\(row\) {
  const result = {};
  for \(const [excelKey, internalKey] of Object.entries\(COLUMN_MAP\)\) {
    result[internalKey] = row[excelKey] ?? '';
  }
  return result;
}

const wb = XLSX.readFile\('C:/Users/coben/OneDrive/Documents/Precios Web.xlsx'\);
const sheet = wb.Sheets[wb.SheetNames[0]];
const allRows = XLSX.utils.sheet_to_json\(sheet, { header: 1, defval: '' }\);

const headerRowIndex = allRows.findIndex\(
  \(row\) => Array.isArray\(row\) && String\(row[0]\).trim\(\) === 'Nombre del producto'
\);
console.log\('headerRowIndex:', headerRowIndex\);

const headers = allRows[headerRowIndex].map\(h => String\(h\).trim\(\)\);
console.log\('headers:', headers\);

const dataRows = allRows.slice\(headerRowIndex + 1\).filter\(row => row.some\(c => c !== ''\)\);
const mapped = dataRows.slice\(0, 5\).map\(row => {
  const obj = {};
  headers.forEach\(\(h, i\) => { obj[h] = row[i] ?? ''; }\);
  return mapRawRow\(obj\);
}\);
console.log\('Sample rows:', JSON.stringify\(mapped, null, 2\)\);
console.log\('Total data rows:', dataRows.length\);
")

